var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"방금 터널 4분의 1지점을 지나쳤어요, 연화. 이제 병목 지점까지 그리 멀지 않아요.","JPN":"レンカさん、先ほどトンネルの4分の1地点を通過しました。もうすぐボトルネック地点です。","ENG":"We just passed the one-quarter point of the tunnel, Yeonhwa. The bottleneck isn't far now.","TWN":"剛剛已經通過隧道4分之1的位置了。蓮華，離瓶頸點不遠了。"},"stage":{"bg":"MIND","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"...응. 이제 눈으로도 보여. 엄청 큰 괴물이 지키고 있네.","JPN":"……うん。もう肉眼でも見えるわ。すごく大きな化け物が守ってる。","ENG":"...Yeah. I can see it now. There's a huge monster guarding it.","TWN":"……嗯。我已經看到了，有個很大的怪物守在那裡。"},"stage":{"bg":"MIND","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"준비해둔 이터니움을 이미 절반쯤 쓴 것 같은데, 괜찮겠어요? 돌아올 때의 에너지도 생각하면...","JPN":"用意したエタニウムはすでに半分にまで減っているようですが、大丈夫なんですか？　戻る時のエネルギーも考慮しないと……","ENG":"It looks like you've already used about half of the Eternium we prepared. Will you be all right? Considering the energy you'll need to get back...","TWN":"你準備的永恆之金好像已經用掉一半了，真的沒問題嗎？也要考慮回程的能量。"},"stage":{"bg":"MIND","bgm":"UI_FIERCE_SOPRANO_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"걱정 마. 병목 현상만 해결하면 들어온 입구로 알아서 튕겨져 나올 거라며?","JPN":"心配しないで。ボトルネック現象さえ解決されれば、入ってきた入口まで勝手に弾き飛ばされるのでしょう？","ENG":"Don't worry. If we just resolve the bottleneck, I'll be automatically pushed back out through the entrance I came in from, right?","TWN":"別擔心。只要解決瓶頸，我們就會被自動彈回入口。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"그건 이 작전이 성공했을 때의 얘기죠! 만에 하나라는 게 있는 거잖아요!","JPN":"それはこの作戦が成功した場合の話です！　万が一ということもあるじゃないですか！","ENG":"That's only if this operation succeeds! There's always the chance it won't!","TWN":"那是在作戰成功的情況下！萬一失敗呢！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"...주한.","JPN":"……シスイ。","ENG":"...Joo Han.","TWN":"……周翰。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그 만에 하나에, 우리의 미래가 걸려 있다면... 난 거기에 전부를 걸 거야.","JPN":"その万が一の事態に私たちの未来がかかっているなら……私はそれにすべてをかけるわ。","ENG":"If our future depends on that one chance... then I'll stake everything on it.","TWN":"如果那萬分之一關係到我們的未來……我會賭上一切。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"겪어본 적도 없는 미래가, 당신 목숨보다 소중하다고 어떻게 확신해요?","JPN":"経験したこともない未来が自分の命より大切だなんて、どうして信じられるんですか？","ENG":"How can you be sure a future you've never experienced is more important than your life?","TWN":"你怎麼確定從沒見過的未來，比你的命還重要？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"과거는 오늘만큼 소중히 여길 순 없겠지만... 미래는 내일의 오늘이니까.","JPN":"過去を今日ほどは大切に思えなくても……未来は明日の今日だから。","ENG":"The past may not be as precious as today... but the future is tomorrow's today.","TWN":"或許過去沒有今天重要……但未來是明天的今天。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"난...","JPN":"私は……","ENG":"I...","TWN":"我是……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"내가 본 적 없는 오늘을 지키고 싶어.","JPN":"私が見たことのない今日を守りたいの。","ENG":"want to protect a today I've never seen.","TWN":"想守住我從未見過的今天。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"분명, 어제보다 소중한 풍경이 기다리고 있을 거라고 생각해.","JPN":"きっと、昨日より大切な風景が待っていると思うわ。","ENG":"I'm sure a view more precious than yesterday is waiting there.","TWN":"我相信，那裡一定有比昨天更珍貴的景象在等著我。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"뻔한 말은 하지 않을게요.","JPN":"綺麗事は言いません。","ENG":"I won't say anything obvious.","TWN":"我就不說那些老套的話了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"보고 와요. 당신이 보고 싶은 풍경.","JPN":"見てきてください。あなたが見たい風景を。","ENG":"Go see it. The view you want to see.","TWN":"去看看你想看到的風景吧。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"신호가 미약합니다. 통신이 곧 끊어집니다.","JPN":"信号が弱いです。もうすぐ通信が途切れます。","ENG":"The signal is weakening. Comms will be cut off soon.","TWN":"訊號正在減弱，通訊即將中斷。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"...고마워.","JPN":"……ありがとう。","ENG":"...Thank you.","TWN":"……謝謝。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"지금 갈게.","JPN":"今行くわ。","ENG":"I'm heading out now.","TWN":"我現在就去。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_46"},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"하아, 겨우 다 치웠다.","JPN":"はあ、やっと全部片付いた。","ENG":"Whew, that finally clears them out.","TWN":"呼，總算清理完了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이 고장 난 깡통들, 지난 번에 와서 간신히 치워 놨는데 전부 멀쩡하게 돌아다녀서 혼났네요.","JPN":"この壊れたボロ缶たち、この前来た時にやっとの思いで片付けたのに、全部元通りになってて死ぬかと思いました。","ENG":"These broken tin cans. We barely cleared them out last time we were here, and they gave us a real hard time being all up and moving again.","TWN":"上次好不容易才清乾淨這些破爛鐵罐，結果現在又全部完好無缺地跑出來。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"어쩔 수 없지. 그 지난 번은 미래고, 여긴 과거니까.","JPN":"仕方ないよ。その「この前」は未来で、ここは過去なんだから。","ENG":"It couldn't be helped. That last time was the future, and this is the past.","TWN":"沒辦法。那個上次是未來，這裡是過去。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"숨지 않는군.","JPN":"隠れないんだな。","ENG":"You're not hiding.","TWN":"你們沒有躲起來啊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SHADOW_EXILER_NPC_QM","text":{"KOREA":"여기까지 올 줄은 몰랐군요.","JPN":"ここまで来るとは思いませんでした。","ENG":"I didn't expect you to make it this far.","TWN":"沒想到你們真的能到這裡。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...스완.","JPN":"……スワン。","ENG":"...Swan.","TWN":"……史旺。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"엑자일러 사냥꾼을 피해, 클리파의 틈새에 얌전히 숨어 있다고 생각했는데 말이죠.","JPN":"エグザイラーハンターの目を逃れ、クリファの狭間に大人しく隠れていましたのに。","ENG":"I thought I was quietly hiding in a gap within the Qlipha to avoid the Exile Hunters.","TWN":"我還以為你們會躲避流放者獵人，乖乖躲在逆卡巴拉的縫隙裡。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어쩌죠? 역시 싸워야 할까요?","JPN":"どうしましょう？　やっぱり戦いますか？","ENG":"What should we do? Do we have to fight after all?","TWN":"怎麼辦？還是得戰鬥嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"나는 널 없앨 생각이 없다.","JPN":"お前を殺す気はない。","ENG":"I have no intention of eliminating you.","TWN":"我沒有要消滅你的打算。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"엑자일러도 아닌 사도 녀석을 추방해봐야, 어차피 다시 돌아올 테고 말이지.","JPN":"エグザイラーでもない使徒を追放したって、どうせまた戻ってくるだろうしな。","ENG":"Even if I banish an Apostle who isn't an Exile, they'll just come back anyway.","TWN":"就算放逐一個不是流放者的使徒，你也會再回來。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"거기까지 알고 있다니, 당신들도 이쪽 세계 사람은 아니겠군요.","JPN":"そこまで知っているということは、あなたたちもこちらの世界の者ではないのですね。","ENG":"So you know that much. Then you're not people of this world either.","TWN":"既然知道這些，你們果然不是這個世界的人。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"게다가 그쪽은... 세피라의 파편.","JPN":"それに、そちらは……セフィラの破片。","ENG":"And that one over there... the Fragment of Sephira.","TWN":"而且那邊的是……塞菲拉的碎片。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아직 이 세상에 발현되지도 않았을 존재가 절 찾아왔다는 건, 이미 어딘가에서 클리포트의 규칙에 어긋나는 일이 벌어졌다는 뜻일 테죠.","JPN":"まだこの世界に発現していないはずの存在が私を訪ねてきたということは、すでにどこかでクリフォトの規則を破った事態が起きたという意味なのでしょう。","ENG":"The fact that a being who hasn't even manifested in this world yet has come to see me must mean something has already happened somewhere that violates the rules of Qliphoth.","TWN":"一個尚未在這個世界顯現的存在卻來找我，代表某處已經發生了違反逆卡巴拉規則的事。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저희는 미래에서 왔거든요.","JPN":"私たち未来から来たんです。","ENG":"We came from the future.","TWN":"我們來自未來。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"스완을 대신해, 아이린 애들러가 머무는 시간선에서요.","JPN":"スワンに代わって、アイリーン・アドラーがいる時間線から。","ENG":"From the timeline where Irene Adler remains in your place.","TWN":"代替史旺，愛琳．艾德勒留下來的時間線。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"...아이린?","JPN":"……アイリーン？","ENG":"...Irene?","TWN":"……愛琳？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇군요. 당신들은 제가 쓰던 각본의 결말을 알고 있나 보네요.","JPN":"そうですか。あなたたちは私が書いていた脚本の結末を知っているようですね。","ENG":"I see. So you already know how the script I wrote ends.","TWN":"原來如此，看來你們已經知道我劇本的結局了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"관리국은 타기리온과의 결전을 앞두고 있어.","JPN":"管理局はタギリオンとの決戦を目前にしてる。","ENG":"The Administration is about to face its final battle with Thagirion.","TWN":"管理局即將與塔基里翁決戰。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그리고 우리에겐 당신의 거울이 필요해.","JPN":"私たちにはあなたの鏡が必要なんだ。","ENG":"And we need your mirror.","TWN":"而我們需要你的鏡子。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"필요하다- 라...","JPN":"必要、ですか……","ENG":"You need it...?","TWN":"需要－嗎……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신들은 제가 흔쾌히 협조할 것처럼 가볍게 말하시네요.","JPN":"まるで私が快く協力するかのように簡単におっしゃるのですね。","ENG":"You speak as if I would willingly cooperate.","TWN":"你們說得倒是很輕鬆，好像我一定會答應合作。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"너도 알다시피, 이미 벌어진 일을 바꿀 순 없다.","JPN":"お前も知っているとおり、すでに起こったことは変えられない。","ENG":"As you know, what has already happened can't be changed.","TWN":"你也知道，已經發生的事情是無法改變的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"우리가 과거로 와서 거울을 잠시 빌리는 것 정도로, 네 녀석의 계획이 틀어지진 않을 거야.","JPN":"私たちが過去に来て鏡を少し借りたくらいで、貴様の計画に支障は出ないはずだ。","ENG":"Even if we came to the past and borrowed your mirror for a moment, it wouldn't disrupt your plan.","TWN":"我們只是來過去借一下鏡子，不會影響你的計畫。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요.","JPN":"そうですね。","ENG":"That's true.","TWN":"是啊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신들이 정말 미래에서 왔다면 제가 여기서 어떤 판단을 하건 결과는 변하지 않겠죠.","JPN":"あなたたちが本当に未来から来たのなら、私がここでどんな判断をしようとも結果は変わらないでしょう。","ENG":"If you really did come from the future, then whatever decision I make here won't change the outcome.","TWN":"如果你們真的來自未來，那不管我現在做什麼決定，結果都不會改變。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 당신들 역시 타기리온이란 난관을 넘어서지 못한 건 마찬가지군요.","JPN":"ですが、あなたたちもまたタギリオンという難関を乗り越えられなかったことは同じなのですね。","ENG":"But it seems you still haven't overcome the obstacle that is Thagirion either.","TWN":"但你們也一樣，還沒跨越塔基里翁這個難關。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"맞아.","JPN":"そうだよ。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그래서 해결책을 찾기 위해 여기로 온 거야.","JPN":"だから解決方法を探すためにここに来たんだ。","ENG":"That's why we came here to find a solution.","TWN":"所以我們才會來這裡找答案。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이해했습니다.","JPN":"理解しました。","ENG":"I understand.","TWN":"我明白了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗, 이해했다면서 무기는 왜 꺼내는 거죠?","JPN":"あっ、理解したのになんで武器を取るんですか？","ENG":"Then why are you drawing your weapon if you understand?!","TWN":"欸？既然明白了，為什麼還要拿武器？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신들에게 어떤 사정이 있건, 저는 타기리온의 사도로서 이곳을 지켜야 하니까요.","JPN":"あなたたちにどんな事情があるにせよ、私はタギリオンの使徒としてここを守らなければいけませんので。","ENG":"No matter what circumstances you may have, as an Apostle of Thagirion, I must protect this place.","TWN":"不管你們有什麼理由，作為塔基里翁的使徒，我必須守住這裡。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"사도라는 운명이 가진 속박의 무게를... 당신이라면 저만큼 잘 이해하고 있겠죠.","JPN":"使徒という運命が持っている束縛の重さ……あなたなら私と同じくらい、よく理解しているでしょう。","ENG":"The weight of the fate that comes with being an Apostle... you understand it as well as I do, don't you?","TWN":"你應該比任何人都懂……使徒這個命運所背負的束縛重量。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇지 않나요? 발키리.","JPN":"そうではありませんか？　ヴァルキリー。","ENG":"Isn't that right, Valkyrie?","TWN":"不是嗎？女武神。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"알겠다. 빨리 끝내지.","JPN":"分かった。すぐ終わらせよう。","ENG":"All right. Let's finish this quickly.","TWN":"知道了，那就快點結束吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"다이애나 씨, 저희가 상대하는 인형들 수가 아까보다 많아진 것 같지 않나요?","JPN":"ダイアナさん、僕たちが相手している人形の数がさっきより増えている気がするんですが。","ENG":"Diana, doesn't it feel like the number of dolls we're facing has increased since earlier?","TWN":"黛安娜，我們要對付的人偶好像比剛才多了。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"실제로 늘었어. 아무래도 소프라노 녀석들의 음파 공격이 차원균열에 구멍을 내고 있는 것 같아.","JPN":"実際に増えた。どうやらソプラノのやつらの音波攻撃が次元亀裂に穴を開けているようだ。","ENG":"It actually has. It seems the Sopranos' sonic attacks are tearing holes in the dimensional rift.","TWN":"確實變多了。看來那些女高音的音波攻擊正在打開次元裂縫。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"역시, 소모전으론 결판이 나지 않겠군요.","JPN":"やはり、消耗戦では決着がつかないですね。","ENG":"As expected, this won't be settled through a war of attrition.","TWN":"果然沒辦法靠消耗戰解決。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"...다른 분들은 함선을 지켜주세요.","JPN":"……皆さんは艦船を守ってください。","ENG":"...Everyone else, please protect the ship.","TWN":"……其他人守住艦船。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"대장? 어떻게 하실 생각이죠?","JPN":"隊長、どうするつもりですか？","ENG":"Commander? What are you planning to do?","TWN":"隊長？你打算怎麼做？"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"인형은 침식체처럼 저희에게 적개심을 갖고 덤비는 게 아녜요. 명령에 따라 움직이는 거죠.","JPN":"人形は侵食体のように僕たちに敵対心を抱いて攻撃してくるわけではありません。ただ命令に従っているだけなんです。","ENG":"The dolls aren't attacking us out of hostility like C.O.s. They're moving according to orders.","TWN":"人偶不像侵蝕體那樣出於敵意攻擊我們，它們只是按照命令行動。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"방금 전까지 녀석들의 움직임을 몇 가지 방식으로 시험해봤는데, 아무래도 소프라노를 지키는 게 최우선 목표인 것 같더군요.","JPN":"さっきまでやつらの動きをいくつかの方法で試してみたんですが、どうやらソプラノを守ることが最優先目標のようです。","ENG":"I tested their movement patterns in several ways just now, and it seems their top priority is protecting the Sopranos.","TWN":"剛才我試探了幾種方式，看來它們的首要任務是保護女高音。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그 말은 즉, 저 큰 녀석이 위험에 처하는 순간 인형들은 다른 걸 포기하고 가장 위협이 되는 대상에게 달려들 거란 겁니다.","JPN":"つまり、あの大きなやつが危険に陥った瞬間、人形たちは他を捨て、最も脅威的な対象に飛びかかるはずなんです。","ENG":"Which means the moment that large one is put in danger, the dolls will abandon everything else and rush toward whatever poses the greatest threat.","TWN":"也就是說，只要那個傢伙陷入危險，人偶就會放棄其他目標，衝向最具威脅性的人。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"일리가 있네. 개체 분포도가 소프라노를 중심으로 가장 밀집해있어.","JPN":"一理あるね。個体の分布度がソプラノを中心に一番密集している。","ENG":"That makes sense. Their distribution density is highest around the Sopranos.","TWN":"有道理。人偶的確實是以女高音為中心，分布最密集。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"하지만 인형이 작동하는 원리를 알았다고 해도, 그걸 어떻게 이용하려고?","JPN":"人形が作動する原理は分かったけど、それをどうやって利用するつもり？","ENG":"But even if we understand how the dolls operate, how are you planning to use that?","TWN":"但就算知道人偶的運作原理，你打算怎麼利用？"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"간단해요. 전 지금부터 소프라노를 공격해 인형들의 제일 큰 위협이 될 겁니다.","JPN":"簡単です。僕は今からソプラノを攻撃して、人形たちの最大の脅威となります。","ENG":"It's simple. From this point on, I'll attack the Sopranos and become their greatest threat.","TWN":"很簡單。我現在要去攻擊女高音，成為人偶最大的威脅。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그럼 소프라노를 중심으로 인형들이 모일 테니, 그 사이에 함선이 포격을 전부 쏟아붓는 거죠.","JPN":"そうすればソプラノを中心に人形が集まってくるはずなので、その間に艦船が全力で砲撃を浴びせるんです。","ENG":"Then the dolls will gather around the Sopranos, and in that moment the ship will unleash all its firepower at once.","TWN":"這樣人偶就會集中到女高音周圍，那時艦船就傾瀉所有炮火。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"애초에 저 우글거리는 무리를 전부 뚫고 어떻게 저기까지 들어갈 방법은 있어?","JPN":"でも、あのうじゃうじゃした群れを抜けて、あそこまで入る方法なんてある？","ENG":"Is there even a way to break through that swarm and get over there in the first place?","TWN":"但要怎麼突破那群密密麻麻的人偶到那裡？"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"길을 여는 건 제가 돕겠습니다.","JPN":"道を開くのは私が手伝います。","ENG":"I'll help open a path.","TWN":"我來幫忙開路。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"무리할 필요 없어요, 지수 씨.","JPN":"無理する必要はありませんよ、シノさん。","ENG":"There's no need to push yourself, Jisoo.","TWN":"不用勉強，智秀。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그 역할엔 시윤 군의 검이 가장 적합할 것 같거든요.","JPN":"その役割は、シリュウ君の剣が一番適していると思いますから。","ENG":"I think Shiyoon's sword is best suited for that role.","TWN":"時雲的劍比較適合這個角色。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"제 검으로 적진 한복판에 마왕님을 밀어넣는다라-","JPN":"僕の剣で敵陣の真ん中に魔王様を押し込む、ですか……","ENG":"Using my sword to throw the Demon Lord right into the middle of enemy lines...","TWN":"用我的劍把魔王送進敵陣中央—"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"저에겐 나쁘지 않은 제안이네요.","JPN":"悪くない提案ですね。","ENG":"That doesn't sound like a bad proposal to me.","TWN":"對我來說倒是個不錯的提議。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 후배님에게 신뢰 받다니 기쁘네.","JPN":"はは、後輩に信用してもらえて嬉しいよ。","ENG":"Haha, I'm glad to have earned the trust of my juniors.","TWN":"哈哈，被後輩信任真開心。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"들어가는 게 성공한다고 해도, 그 뒤엔 어떻게 빠져나올 셈이지?","JPN":"入ることに成功したとしても、その後どうやって抜け出すつもりだ？","ENG":"Even if getting in succeeds, how are you planning to get back out afterward?","TWN":"就算成功衝進去，你打算怎麼撤退？"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"빠져나오는 건 계획에 없습니다.","JPN":"抜け出す計画はありません。","ENG":"Getting out isn't part of the plan.","TWN":"撤退不在計畫內。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"...뭐?","JPN":"……何だって？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ADMIN_OMEN_OPR_NULL","text":{"KOREA":"또 다른 균열 발생...! 차원터널의 구조 안정성이 붕괴 임계치에 도달했습니다!!","JPN":"また亀裂が発生……！　次元トンネルの構造安定性が崩壊臨界数値に到達しました！！","ENG":"Another rift forming...! The dimensional tunnel's structural stability has reached its collapse threshold!!","TWN":"又出現新的裂縫了……！次元隧道的結構穩定性已經到達崩潰臨界值！！"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L8_1","type":"dialog","speaker":"ADMIN_OMEN_OPR_NULL","text":{"KOREA":"곧 터널이 무너지고 말 겁니다!","JPN":"もうすぐトンネルが崩壊してしまいます！","ENG":"The tunnel is about to collapse!","TWN":"隧道很快就會崩塌！"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"시작해보죠.","JPN":"始めましょう。","ENG":"Let's begin.","TWN":"開始吧。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그럼, 실례하겠습니다.","JPN":"では、失礼します。","ENG":"Then, excuse me.","TWN":"失禮了。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"자, 잠깐- 소프라노의 근처까지 가긴 했는데, 저건 너무 높은 거 아냐?","JPN":"ま、待って……ソプラノの近くには行ったけど、あれじゃ高すぎるんじゃない？","ENG":"W-wait! He made it near the Soprano, but isn't that too high up?","TWN":"等、等一下—雖然已經到女高音附近了，但也太高了吧？"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 공중에서 내려다보는 편이 상황을 파악하는 데 도움이 될 것 같아서요.","JPN":"ハハ、空中から見下ろした方が状況を把握するには便利かなと思いまして。","ENG":"Haha, I figured it would help to get a better view from above.","TWN":"哈哈，從空中俯視比較容易掌握狀況。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"여차하면 제가 밑에서 받아드릴까요?","JPN":"何なら、僕が下で受け止めてあげましょうか？","ENG":"If something happens, should I catch you from below?","TWN":"要是出什麼意外，我在下面接住你吧？"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"...괜찮아요.","JPN":"……大丈夫です。","ENG":"...I'll be fine.","TWN":"……沒關係。"},"stage":{"bg":"BLACK","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"확실히- 내려다보는 편이 낫네.","JPN":"確かに……見下ろした方が分かりやすい。","ENG":"Yeah... This view is better.","TWN":"確實—從上面俯視比較好。"},"stage":{"bg":"BLACK","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"소프라노의 머리를 ...힘으로 뜯어냈어?","JPN":"ソプラノの頭を……力づくでもぎ取った？","ENG":"He... tore the Soprano's head off with sheer force?","TWN":"他把女高音的頭……用力扯下來了？"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"조심해! 전부 그쪽으로 가고 있어!","JPN":"気をつけて！　全部そっちに向かってるよ！","ENG":"Watch out! They're all heading your way!","TWN":"小心！全部都往那邊過去了！"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"어떻게 됐지? 살아는 있나?","JPN":"どうだ？　生きてはいるのか？","ENG":"What happened? Is he alive?","TWN":"怎麼樣？還活著嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"...모르겠어. 너무 많은 숫자가 한꺼번에 몰려들고 있어서 형체도 보이지 않아.","JPN":"……分かんない。大勢が一気に押し寄せてて、姿も見えないよ。","ENG":"...I don't know. Too many of them rushed in at once! I can't even see him anymore.","TWN":"……不知道。一次湧上太多，連人影都看不見了。"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ADMIN_OMEN_OPR_NULL","text":{"KOREA":"격전지로부터 국소적인 클리파 에너지 감지...!","JPN":"激戦地から局所的なクリファエネルギーを感知……！","ENG":"Localized Qlipha energy detected from the battlefield...!","TWN":"從激戰區域偵測到局部的逆卡巴拉能量……！"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L35_1","type":"dialog","speaker":"ADMIN_OMEN_OPR_NULL","text":{"KOREA":"위험도 레벨, 빠르게 올라갑니다!","JPN":"危険度レベル、急上昇します！","ENG":"Danger level rising rapidly!","TWN":"危險等級正在快速上升！"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"함선 밖 인원들은 여파에 대비해. 차원균열에서 최대한 떨어지고 엄폐해라!","JPN":"艦船の外にいる人員は余波に備えろ。次元亀裂からなるべく離れて身を隠せ！","ENG":"Everyone outside the ship, prepare for the aftershock. Move as far away from the dimensional rift as possible and take cover!","TWN":"船外的人員注意衝擊波。盡量遠離次元裂縫並找地方掩護！"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"엄폐? 어디로?!","JPN":"身を隠す？　どこに！？","ENG":"Take cover? Where?!","TWN":"掩護？要躲去哪裡？！"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"제 뒤로 오세요!","JPN":"僕の後ろへ！","ENG":"Get behind me!","TWN":"到我後面來！"},"stage":{"bg":"MIND","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이 진동... 터널이 무너지려는 징조일까?","JPN":"この振動……トンネルが崩壊する前兆なのかしら？","ENG":"This vibration... Is the tunnel about to collapse?","TWN":"這個震動……是隧道要崩塌的前兆嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"장막 너머가 근원지라면... 서두르는 게 좋겠네.","JPN":"幕の向こうが根源地なら……急いだ方がいいわね。","ENG":"If the source is beyond the veil... we'd better hurry.","TWN":"如果源頭在那層帷幕後面……得加快速度了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"으윽, 골머리야.","JPN":"ううっ、頭痛い。","ENG":"Ugh, my head...","TWN":"唔……頭好痛。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"방금 그건 뭐였어? 핵폭발?","JPN":"今のは何だったの？　核爆発？","ENG":"What was that just now? A nuclear explosion?","TWN":"剛剛那是什麼？核爆嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"음... 위력은 비슷했던 것 같네요. 핵연료 대신 다른 에너지가 쓰이긴 했지만요.","JPN":"うーん……それくらいの威力だったみたいですね。核燃料の代わりに別のエネルギーが使われましたけど。","ENG":"Hmm... The power seemed similar. Though it used a different kind of energy instead of nuclear fuel.","TWN":"嗯……感覺威力差不多。不過用的不是核燃料，而是別的能量。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"다른 에너지...?","JPN":"別のエネルギー……？","ENG":"Different energy...?","TWN":"別的能量……？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"멀쩡히 걸어 나왔네.","JPN":"何事もなかったかのように出てきたね。","ENG":"He just walked out like nothing happened.","TWN":"居然若無其事地走出來了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"방금 그 폭발, 나유빈 씨가 일으킨 거야?","JPN":"今の爆発って、イチノセさんが起こしたの？","ENG":"Was that explosion just now caused by you, Na Yubin?","TWN":"剛剛那場爆炸，是羅瑜斌引起的嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"다들 무사한 걸 보니 힘 조절은 적당했던 것 같군요.","JPN":"みんな無事なところを見ると、適当な力加減だったみたいですね。","ENG":"Seeing that everyone's safe, it seems I adjusted the output appropriately.","TWN":"大家都沒事，看來力道控制得剛剛好。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"그게... 힘 조절을 한 거라고?","JPN":"あれで……加減してたの？","ENG":"That was... holding back?","TWN":"那還叫……控制過力道？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"방금 그게 당신이 가진 마왕의 힘이란 거군.","JPN":"今のがあなたが持っている魔王の力ってわけだ。","ENG":"So that was the Demon Lord's power you possess.","TWN":"剛剛那就是你擁有的魔王之力吧。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"진작 썼다면 좋았을 텐데, 왜 그러지 않았지?","JPN":"もっと早く使ってくれればよかったのに、どうしてそうしなかった？","ENG":"It would've been nice if you'd used it earlier. Why didn't you?","TWN":"早點用不就好了？為什麼不一開始就用？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"마왕의 권능은 규칙이 닿지 않는 무질서, 즉 클리파 에너지의 의존도가 큰편입니다. 차원터널에서 필요 이상의 클리파 에너지를 끌어들이면 터널이 팽창할 위험이 있거든요.","JPN":"魔王の権能は規則が影響しない無秩序、すなわちクリファエネルギーへの依存度が高いです。次元トンネルで必要以上のクリファエネルギーを引き寄せると、トンネルが膨張する恐れがあるんですよ。","ENG":"The Demon Lord's power depends heavily on disorder beyond the reach of rules–in other words, Qlipha energy. If I draw in more Qlipha energy than necessary inside the dimensional tunnel, there's a risk the tunnel could expand.","TWN":"魔王的權能仰賴的是規則無法觸及的混沌，也就是逆卡巴拉能量。如果在次元隧道裡引入過量的逆卡巴拉能量，隧道有膨脹的風險。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"타기리온의 군세가 격전 도중 마구잡이로 낸 균열이 에너지 배출구 역할을 해주지 않을까 했는데, 결과적으로 제 생각이 맞았군요.","JPN":"タギリオンの軍勢が激戦途中にむやみに発生させた亀裂が、エネルギーの排出口の役目を果たしてくれるんじゃないかと思っていましたが、結果的にその考えが当たりましたね。","ENG":"I thought the rifts the army of Thagirion created recklessly during the battle might serve as energy outlets. It seems my assumption was correct.","TWN":"我原本想說塔基里翁的軍勢在激戰中胡亂製造的裂縫，也許能當作能量排出口。結果看來我的判斷是對的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 하마터면 터널이 팽창해서 저희 모두 허수 차원으로 날아갈 뻔 했다는 거네요.","JPN":"ハハ、一歩間違えればトンネルが膨張して、僕たち全員虚数次元に飛ばされていたってことですね。","ENG":"Haha, so the tunnel could've expanded and sent all of us flying into the imaginary dimension.","TWN":"哈哈，差點讓隧道膨脹，把我們全都丟進虛空次元了呢。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"그게 웃으면서 할 소리야?!","JPN":"それ、笑いながらする話じゃないよね！？","ENG":"Is that something to laugh about?!","TWN":"這是可以笑著說的事嗎？！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"인형들이... 또 쏟아져 들어오고 있어. 쉴 틈도 주지 않네.","JPN":"人形が……また溢れ出てきた。休む暇がないな。","ENG":"The dolls... They're pouring in again. They won't even give us a moment to rest.","TWN":"人偶們……又湧過來了，完全不給我們喘息的時間。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"하지만 이 정도 규모라면, 앞으로 나아가는 덴 문제가 없겠어.","JPN":"だがこの程度の規模なら、前に進むことに問題はなさそうだ。","ENG":"But at this scale, it shouldn't be a problem to keep advancing.","TWN":"不過這種規模，繼續往前推進應該沒問題。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"터널을 막고 있는 장막이 멀지 않아요.","JPN":"トンネルを塞いでいる幕まであと少しです。","ENG":"The veil blocking the tunnel isn't far now.","TWN":"阻擋隧道的帷幕已經不遠了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"...그래. 달님 팀이 도착하기 전에, 얼른 저 망할 장애물을 치워버려야지.","JPN":"……そうだね。お月様チームが到着する前に、早くあの邪魔物を消さないと。","ENG":"...Right. Before Team Moon arrives, we need to clear that damn obstacle out of the way.","TWN":"……好。在月亮隊抵達前，先清掉該死的障礙吧。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"가자!!","JPN":"行こう！！","ENG":"Let's go!!","TWN":"走吧！！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};